final class Physics {
    void calculateVelocity(double[] p1, double[] p2, double dt, double[] out) {
        out[0] = (p2[0] - p1[0]) / dt;
        out[1] = (p2[1] - p1[1]) / dt;
        out[2] = (p2[2] - p1[2]) / dt;
    }
}

