}

final class PhysicsAllocating {
    Vector3 calculateVelocity(Vector3 p1, Vector3 p2, double dt) {
        Vector3 out = new Vector3(); // new object every call
        out.x = (p2.x - p1.x) / dt;
        out.y = (p2.y - p1.y) / dt;
        out.z = (p2.z - p1.z) / dt;
        return out;
    }
}

