final class Validator {
    static final int VALID = 0;
    static final int ERROR_NULL = 1;
    static final int ERROR_EMPTY = 2;

    int validate(String input) {
        if (input == null) return ERROR_NULL;
        if (input.isEmpty()) return ERROR_EMPTY;
        return VALID;
    }
}

